INSERT INTO `fqsi_options` (`option_id`, `option_name`, `option_value`, `autoload`) VALUES (60388,'_ally_notifications','a:2:{s:7:\"timeout\";i:1772042945;s:5:\"value\";s:2720:\"[{\"id\":\"one-launch\",\"title\":\"Introducing Elementor One\",\"description\":\"The complete website building experience. All the tools to create, optimize, and manage websites, unified under one roof.\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/ally\\/v1\\/images\\/one-launch.png\",\"chipTags\":[\"New Launch\"],\"cta\":\"Explore Elementor One\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/ally-whats-new-one-launch\"},{\"id\":\"ally-headings-remediation-09182025\",\"title\":\"New: Headings Remediation Management!\",\"description\":\"Review and correct headings hierarchy for better accessibility! Detect Missing H1, Multiple H1, skipped levels and more.\",\"topic\":\"Ally\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/ally\\/v1\\/images\\/headings-remediation.png\",\"chipTags\":[\"New Feature\"],\"link\":\"https:\\/\\/go.elementor.com\\/acc-whats-new-headings\",\"readMoreText\":\"Learn More\"},{\"id\":\"widget-redesign-09042025\",\"title\":\"Explore the updated usability widget!\",\"description\":\"Check out the new widget look & feel! Now with organized categories for simpler navigation and a mobile-first layout that creates a more intuitive experience for your site visitors.\",\"topic\":\"Ally\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/ally\\/v1\\/images\\/widget_redesign.png\",\"chipTags\":[\"New Feature\"]},{\"id\":\"ally-assistant-07042025\",\"title\":\"Meet Ally Assistant! Scan pages, detect accessibility violations, and fix them fast - effortlessly\",\"description\":\"Find and fix 180+ accessibility violations required by WCAG 2.1 AA. Ally Assistant walks you through each step, with the option to use AI to help fix text and code along the way.\",\"topic\":\"Ally\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/ally\\/v1\\/images\\/ally-assistant.png\",\"chipTags\":[\"New Feature\"],\"link\":\"https:\\/\\/go.elementor.com\\/acc-assistant-whats-new\",\"readMoreText\":\"Learn More\"},{\"id\":\"site-ally-custom-icon-05132025\",\"title\":\"New! Add a Custom Icon\",\"description\":\"You can now upload your own custom icon to personalize the Ally widget\'s appearance.\",\"topic\":\"Ally\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/ally\\/v1\\/images\\/Custom_icon.svg\",\"chipTags\":[\"New Feature\"]},{\"id\":\"site-ally-link-trigger-05132025\",\"title\":\"New! Trigger Ally from any link\",\"description\":\"Use a Dynamic Tag in Elementor or a custom link in Gutenberg to open the Ally widget from anywhere on your site.\",\"topic\":\"Ally\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/ally\\/v1\\/images\\/Dynamic_tag.svg\",\"chipTags\":[\"New Feature\"]},{\"id\":\"site-ally-corner-radius-05132025\",\"title\":\"New! Custom Corner Radius\",\"description\":\"You can now customize the corner radius of the Ally widget for a more tailored look.\",\"topic\":\"Ally\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/ally\\/v1\\/images\\/Radius.svg\",\"chipTags\":[\"New Feature\"]}]\";}','off');
