INSERT INTO `fqsi_options` (`option_id`, `option_name`, `option_value`, `autoload`) VALUES (60424,'_image-optimizer_notifications','a:2:{s:7:\"timeout\";i:1772057354;s:5:\"value\";s:2424:\"[{\"id\":\"one-launch\",\"title\":\"Introducing Elementor One\",\"description\":\"The complete website building experience. All the tools to create, optimize, and manage websites, unified under one roof.\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/image-optimizer\\/v1\\/images\\/one-launch.png\",\"chipTags\":[\"New Launch\"],\"cta\":\"Explore Elementor One\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/io-whats-new-one-launch\"},{\"id\":\"optimisation-details\",\"title\":\"New! Detailed Optimization Summary by Image Size\",\"description\":\"Get a clearer picture of your media performance! The new optimization summary shows exactly how each image size is compressed and resized\\u2014plus, you\\u2019ll know if any size didn\\u2019t go through and can quickly try again. Smarter insights, smoother workflows.\",\"topic\":\"Image Optimizer\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/image-optimizer\\/v1\\/images\\/file-size-image-status.png\",\"chipTags\":[\"New Feature\"]},{\"id\":\"ally-notification\",\"title\":\"Just released! Ally - a new plugin for web accessibility & usability\",\"description\":\"Ally simplifies the complexities of making your website more accessible. With new regulations here and coming, making your website more usable and inclusive is no longer just an option, but a must.\",\"topic\":\"Ally by Elementor\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/image-optimizer\\/v1\\/images\\/ally-notification.png\",\"chipTags\":[\"New Plugin\"],\"cta\":\"Get it free\",\"ctaLink\":\"https:\\/\\/wordpress.org\\/plugins\\/pojo-accessibility\\/\",\"conditions\":[[{\"type\":\"plugin\",\"operator\":\"!=\",\"plugin\":\"pojo-accessibility\\/pojo-accessibility.php\"}]]},{\"id\":\"convert-to-avif\",\"title\":\"Speed Your Site with AVIF\",\"description\":\"Keep traffic on your site longer with faster loading pages. Image Optimizer now supports the cutting edge AVIF image format that gives you the lightest file sizes possible!.\",\"topic\":\"Image Optimizer\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/image-optimizer\\/v1\\/images\\/community-post.png\",\"chipTags\":[\"New Feature\"],\"link\":\"https:\\/\\/go.elementor.com\\/avif-blog\",\"readMoreText\":\"Learn More\"},{\"id\":\"image-size-bloat\",\"title\":\"WordPress image size bloat\",\"description\":\"Do you really need all those image sizes on your site? Discover how WordPress handles your uploads\\u2014and how to take control of image versions, compression, and performance.\",\"topic\":\"Image Optimizer\",\"link\":\"https:\\/\\/go.elementor.com\\/wp-sizes-blog\",\"readMoreText\":\"Learn More\"}]\";}','off');
