INSERT INTO `fqsi_options` (`option_id`, `option_name`, `option_value`, `autoload`) VALUES (130928,'wcpay_recommended_payment_methods__US__en_US','a:3:{s:4:\"data\";a:12:{i:0;a:8:{s:2:\"id\";s:4:\"card\";s:4:\"type\";s:7:\"enabled\";s:8:\"category\";s:7:\"primary\";s:5:\"title\";s:17:\"Credit/debit card\";s:11:\"description\";s:40:\"Accepts all major credit and debit cards\";s:8:\"priority\";i:1;s:8:\"required\";b:1;s:4:\"icon\";s:44:\"https://s0.wp.com/i/payment-methods/card.svg\";}i:1;a:8:{s:2:\"id\";s:9:\"apple_pay\";s:4:\"type\";s:7:\"enabled\";s:8:\"category\";s:7:\"primary\";s:5:\"title\";s:9:\"Apple Pay\";s:11:\"description\";s:65:\"Give your shoppers an easy and secure way to pay, with Apple Pay.\";s:8:\"priority\";i:2;s:8:\"required\";b:0;s:4:\"icon\";s:49:\"https://s0.wp.com/i/payment-methods/apple_pay.svg\";}i:2;a:8:{s:2:\"id\";s:10:\"google_pay\";s:4:\"type\";s:7:\"enabled\";s:8:\"category\";s:7:\"primary\";s:5:\"title\";s:10:\"Google Pay\";s:11:\"description\";s:70:\"Offer customers a fast and secure checkout experience with Google Pay.\";s:8:\"priority\";i:3;s:8:\"required\";b:0;s:4:\"icon\";s:50:\"https://s0.wp.com/i/payment-methods/google_pay.svg\";}i:3;a:8:{s:2:\"id\";s:6:\"woopay\";s:4:\"type\";s:7:\"enabled\";s:8:\"category\";s:7:\"primary\";s:5:\"title\";s:6:\"WooPay\";s:11:\"description\";s:91:\"Boost conversions and customer loyalty by offering a secure way to pay with a single click.\";s:8:\"priority\";i:4;s:8:\"required\";b:0;s:4:\"icon\";s:46:\"https://s0.wp.com/i/payment-methods/woopay.svg\";}i:4;a:8:{s:2:\"id\";s:6:\"affirm\";s:4:\"type\";s:7:\"enabled\";s:8:\"category\";s:7:\"primary\";s:5:\"title\";s:6:\"Affirm\";s:11:\"description\";s:49:\"Allow your shoppers to pay over time with Affirm.\";s:8:\"priority\";i:5;s:8:\"required\";b:0;s:4:\"icon\";s:46:\"https://s0.wp.com/i/payment-methods/affirm.svg\";}i:5;a:8:{s:2:\"id\";s:17:\"afterpay_clearpay\";s:4:\"type\";s:7:\"enabled\";s:8:\"category\";s:7:\"primary\";s:5:\"title\";s:17:\"Cash App Afterpay\";s:11:\"description\";s:60:\"Allow your shoppers to pay over time with Cash App Afterpay.\";s:8:\"priority\";i:6;s:8:\"required\";b:0;s:4:\"icon\";s:57:\"https://s0.wp.com/i/payment-methods/afterpay_clearpay.svg\";}i:6;a:8:{s:2:\"id\";s:6:\"klarna\";s:4:\"type\";s:7:\"enabled\";s:8:\"category\";s:7:\"primary\";s:5:\"title\";s:6:\"Klarna\";s:11:\"description\";s:49:\"Allow your shoppers to pay over time with Klarna.\";s:8:\"priority\";i:7;s:8:\"required\";b:0;s:4:\"icon\";s:46:\"https://s0.wp.com/i/payment-methods/klarna.svg\";}i:7;a:8:{s:2:\"id\";s:10:\"bancontact\";s:4:\"type\";s:9:\"available\";s:8:\"category\";s:9:\"secondary\";s:5:\"title\";s:10:\"Bancontact\";s:11:\"description\";s:102:\"Bancontact is a bank redirect payment method offered by more than 80% of online businesses in Belgium.\";s:8:\"priority\";i:8;s:8:\"required\";b:0;s:4:\"icon\";s:50:\"https://s0.wp.com/i/payment-methods/bancontact.svg\";}i:8;a:8:{s:2:\"id\";s:3:\"eps\";s:4:\"type\";s:9:\"available\";s:8:\"category\";s:9:\"secondary\";s:5:\"title\";s:3:\"EPS\";s:11:\"description\";s:68:\"Accept your payment with EPS — a common payment method in Austria.\";s:8:\"priority\";i:9;s:8:\"required\";b:0;s:4:\"icon\";s:43:\"https://s0.wp.com/i/payment-methods/eps.svg\";}i:9;a:8:{s:2:\"id\";s:5:\"ideal\";s:4:\"type\";s:9:\"available\";s:8:\"category\";s:9:\"secondary\";s:5:\"title\";s:5:\"iDEAL\";s:11:\"description\";s:127:\"iDEAL is a Netherlands-based payment method that allows customers to complete transactions online using their bank credentials.\";s:8:\"priority\";i:10;s:8:\"required\";b:0;s:4:\"icon\";s:45:\"https://s0.wp.com/i/payment-methods/ideal.svg\";}i:10;a:8:{s:2:\"id\";s:3:\"p24\";s:4:\"type\";s:9:\"available\";s:8:\"category\";s:9:\"secondary\";s:5:\"title\";s:10:\"Przelewy24\";s:11:\"description\";s:81:\"Accept payments with Przelewy24 (P24), the most popular payment method in Poland.\";s:8:\"priority\";i:11;s:8:\"required\";b:0;s:4:\"icon\";s:43:\"https://s0.wp.com/i/payment-m