INSERT INTO `fqsi_options` (`option_id`, `option_name`, `option_value`, `autoload`) VALUES (200019,'wpconsent_scanner_data','a:2:{s:4:\"date\";s:19:\"2026-07-19 01:23:52\";s:4:\"data\";a:4:{s:5:\"error\";b:0;s:7:\"scripts\";a:3:{s:9:\"essential\";a:4:{i:0;a:7:{s:4:\"name\";s:8:\"comments\";s:7:\"service\";s:8:\"Comments\";s:4:\"html\";s:0:\"\";s:4:\"logo\";s:48:\"https://cdn.wpconsent.com/services/wordpress.png\";s:3:\"url\";s:0:\"\";s:11:\"description\";s:61:\"These cookies are needed for adding comments on this website.\";s:7:\"cookies\";a:3:{s:14:\"comment_author\";a:2:{s:8:\"duration\";s:7:\"Session\";s:11:\"description\";s:48:\"Used to track the user across multiple sessions.\";}s:20:\"comment_author_email\";a:2:{s:8:\"duration\";s:7:\"Session\";s:11:\"description\";s:48:\"Used to track the user across multiple sessions.\";}s:18:\"comment_author_url\";a:2:{s:8:\"duration\";s:7:\"Session\";s:11:\"description\";s:48:\"Used to track the user across multiple sessions.\";}}}i:1;a:7:{s:4:\"name\";s:22:\"easy_digital_downloads\";s:7:\"service\";s:22:\"Easy Digital Downloads\";s:4:\"html\";s:0:\"\";s:4:\"logo\";s:61:\"https://cdn.wpconsent.com/services/easy-digital-downloads.png\";s:3:\"url\";s:0:\"\";s:11:\"description\";s:113:\"Easy Digital Downloads is a WordPress plugin for selling digital products effortlessly and managing transactions.\";s:7:\"cookies\";a:2:{s:12:\"edd_session_\";a:2:{s:8:\"duration\";s:7:\"Session\";s:11:\"description\";s:50:\"Stores information about the current user session.\";}s:17:\"edd_items_in_cart\";a:2:{s:8:\"duration\";s:7:\"Session\";s:11:\"description\";s:43:\"Stores information about the cart contents.\";}}}i:2;a:7:{s:4:\"name\";s:11:\"woocommerce\";s:7:\"service\";s:11:\"WooCommerce\";s:4:\"html\";s:0:\"\";s:4:\"logo\";s:50:\"https://cdn.wpconsent.com/services/woocommerce.png\";s:3:\"url\";s:0:\"\";s:11:\"description\";s:92:\"WooCommerce is a customizable eCommerce platform for building online stores using WordPress.\";s:7:\"cookies