fasync=&quot;false&quot; data-wpfc-render=&quot;false&quot;&gt;\n		(function () {\n			window.dataLayer = window.dataLayer || [];function gtag(){dataLayer.push(arguments);}\n			\n			let preferences = {\n				marketing: 0,\n				statistics: 0,\n			}\n			\n			// Get preferences directly from cookie\n			const value = `; ` + document.cookie;\n			const parts = value.split(`; wpconsent_preferences=`);\n			if (parts.length === 2) {\n				try {\n					preferences = JSON.parse(parts.pop().split(&#039;;&#039;).shift());\n				} catch (e) {\n					console.error(&#039;Error parsing WPConsent preferences:&#039;, e);\n				}\n			}\n			\n			gtag(&#039;consent&#039;, &#039;default&#039;, {\n				&#039;ad_storage&#039;: preferences.marketing ? &#039;granted&#039; : &#039;denied&#039;,\n				&#039;analytics_storage&#039;: preferences.statistics ? &#039;granted&#039; : &#039;denied&#039;,\n				&#039;ad_user_data&#039;: preferences.marketing ? &#039;granted&#039; : &#039;denied&#039;,\n				&#039;ad_personalization&#039;: preferences.marketing ? &#039;granted&#039; : &#039;denied&#039;,\n				&#039;security_storage&#039;: &#039;granted&#039;,\n				&#039;functionality_storage&#039;: &#039;granted&#039;\n			});\n		})();\n	&lt;/script&gt;\";s:4:\"logo\";s:55:\"https://cdn.wpconsent.com/services/google-analytics.png\";s:3:\"url\";s:35:\"https://policies.google.com/privacy\";s:11:\"description\";s:110:\"Google Analytics is a powerful tool that tracks and analyzes website traffic for informed marketing decisions.\";s:7:\"cookies\";a:13:{s:5:\"_gac_\";a:2:{s:8:\"duration\";s:7:\"90 days\";s:11:\"description\";s:185:\"Contains information related to marketing campaigns of the user. These are shared with Google AdWords / Google Ads when the Google Ads and Google Analytics accounts are linked together.\";}s:6:\"__utma\";a:2:{s:8:\"duration\";s:27:\"2 years after last activity\";s:11:\"description\";s:38:\"ID used to identify users and sessions\";}s:6:\"__utmt\";a:2:{s:8:\"duration\";s:10:\"10 minutes\";s:11:\"description\";s:58:\"Used to monitor number of Google Analytics server requests\";}s:6:\"__utmb\";a:2:{s:8:\"duration\";s:30:\"30 minutes after last activity\";s:11:\"description\";s:225:\"Used to distinguish new sessions and visits. This cookie is set when the GA.js javascript library is loaded and there is no existing __utmb cookie. The cookie is updated every time data is sent to the Google Analytics server.\";}s:6:\"__utmc\";a:2:{s:8:\"duration\";s:24:\"End of session (browser)\";s:11:\"description\";s:155:\"Used only with old Urchin versions of Google Analytics and not with GA.js. Was used to distinguish between new sessions and visits at the end of a session.\";}s:6:\"__utmz\";a:2:{s:8:\"duration\";s:28:\"6 months after last activity\";s:11:\"description\";s:206:\"Contains information about the traffic source or campaign that directed user to the website. The cookie is set when the GA.js javascript is loaded and updated when data is sent to the Google Anaytics server\";}s:6:\"__utmv\";a:2:{s:8:\"duration\";s:27:\"2 years after last activity\";s:11:\"description\";s:185:\"Contains custom information set by the web developer via the _setCustomVar method in Google Analytics. This cookie is updated every time new data is sent to the Google Analytics server.\";}s:6:\"__utmx\";a:2:{s:8:\"duration\";s:9:\"18 months\";s:11:\"description\";s:78:\"Used to determine whether a user is included in an A / B or Multivariate test.\";}s:3:\"_ga\";a:2:{s:8:\"duration\";s:7:\"2 years\";s:11:\"description\";s:25:\"ID used to identify users\";}s:5:\"_gali\";a:2:{s:8:\"duration\";s:10:\"30 seconds\";s:11:\"description\";s:77:\"Used by Google Analytics to determine which links on a page are being clicked\";}s:4:\"_ga_\";a:2:{s:8:\"duration\";s:7:\"2 years\";s:11:\"description\";s:25:\"ID used to identify users\";}s:4:\"_gid\";a:2:{s:8:\"duration\";s:8:\"24 hours\";s:11:\"description\";s:58:\"ID used to identify users for 24 hours after last activity\";}s:4:\"_gat\";a:2:{s:8:\"dur