missed_suggestions__\";a:2:{s:8:\"duration\";s:7:\"1 month\";s:11:\"description\";s:43:\"Count of suggestion dismissals, if enabled.\";}s:21:\"woocommerce_cart_hash\";a:2:{s:8:\"duration\";s:7:\"session\";s:11:\"description\";s:60:\"Helps WooCommerce determine when cart contents/data changes.\";}s:25:\"woocommerce_items_in_cart\";a:2:{s:8:\"duration\";s:7:\"session\";s:11:\"description\";s:60:\"Helps WooCommerce determine when cart contents/data changes.\";}}}s:14:\"wp-consent-api\";a:7:{s:4:\"name\";s:14:\"wp-consent-api\";s:7:\"service\";s:14:\"WP Consent API\";s:4:\"html\";s:0:\"\";s:4:\"logo\";s:53:\"https://cdn.wpconsent.com/services/wp-consent-api.png\";s:3:\"url\";s:0:\"\";s:11:\"description\";s:110:\"WP Consent API is a plugin that standardizes the communication of accepted consent categories between plugins.\";s:7:\"cookies\";a:1:{s:21:\"wp_consent_{category}\";a:2:{s:8:\"duration\";s:7:\"30 days\";s:11:\"description\";s:193:\" Stores your consent preference for a specific cookie category (e.g., functional, marketing). It ensures consistent consent management across WordPress plugins supporting the WP Consent API. \";}}}s:18:\"google-tag-manager\";a:7:{s:4:\"name\";s:18:\"google-tag-manager\";s:7:\"service\";s:18:\"Google Tag Manager\";s:4:\"html\";s:495:\"&lt;script type=&quot;litespeed/javascript&quot;&gt;(function(w,d,s,l,i){w[l]=w[l]||[];w[l].push({&#039;gtm.start&#039;:new Date().getTime(),event:&#039;gtm.js&#039;});var f=d.getElementsByTagName(s)[0],j=d.createElement(s),dl=l!=&#039;dataLayer&#039;?&#039;&amp;l=&#039;+l:&#039;&#039;;j.async=!0;j.src=&#039;https://www.googletagmanager.com/gtm.js?id=&#039;+i+dl;f.parentNode.insertBefore(j,f)})(window,document,&#039;script&#039;,&#039;dataLayer&#039;,&#039;GTM-KS6QGBF4&#039;)&lt;/script&gt;\";s:4:\"logo\";s:47:\"https://cdn.wpconsent.com/services/fallback.png\";s:3:\"url\";s:0:\"\";s:11:\"description\";s:100:\"Google Tag Manager simplifies the management of marketing tags on your website without code changes.\";s:7:\"cookies\";a:2:{s:17:\"cookiePreferences\";a:2:{s:8:\"duration\";s:7:\"2 years\";s:11:\"description\";s:38:\"Registers cookie preferences of a user\";}s:2:\"td\";a:2:{s:8:\"duration\";s:7:\"session\";s:11:\"description\";s:115:\"Registers statistical data on users\' behaviour on the website. Used for internal analytics by the website operator.\";}}}}s:10:\"statistics\";a:1:{s:16:\"google-analytics\";a:7:{s:4:\"name\";s:16:\"google-analytics\";s:7:\"service\";s:16:\"Google Analytics\";s:4:\"html\";s:176:\"&lt;script type=&quot;litespeed/javascript&quot; data-src=&quot;https://www.googletagmanager.com/gtag/js?id=GT-NNMS2FV5&quot; id=&quot;google_gtagjs-js&quot;&gt;&lt;/script&gt;\";s:4:\"logo\";s:55:\"https://cdn.wpconsent.com/services/google-analytics.png\";s:3:\"url\";s:35:\"https://policies.google.com/privacy\";s:11:\"description\";s:110:\"Google Analytics is a powerful tool that tracks and analyzes website traffic for informed marketing decisions.\";s:7:\"cookies\";a:13:{s:5:\"_gac_\";a:2:{s:8:\"duration\";s:7:\"90 days\";s:11:\"description\";s:185:\"Contains information related to marketing campaigns of the user. These are shared with Google AdWords / Google Ads when the Google Ads and Google Analytics accounts are linked together.\";}s:6:\"__utma\";a:2:{s:8:\"duration\";s:27:\"2 years after last activity\";s:11:\"description\";s:38:\"ID used to identify users and sessions\";}s:6:\"__utmt\";a:2:{s:8:\"duration\";s:10:\"10 minutes\";s:11:\"description\";s:58:\"Used to monitor number of Google Analytics server requests\";}s:6:\"__utmb\";a:2:{s:8:\"duration\";s:30:\"30 minutes after last activity\";s:11:\"description\";s:225:\"Used to distinguish new sessions and visits. This cookie is set when the GA.js javascript library is loaded and there is no existing __utmb cookie. The cookie is updated every time data is sent to the Google Analytics server.\";}s:6:\"__utmc\";a:2:{s:8:\"duration\";s:24:\"End of session (browser)\";s:11:\"description\";s:155:\"Used only with old Urchin versions of Google Analytics and not with GA.js. Was used to distinguish between new sessions and visits at the end of a session.\";}s:6:\"__utmz\";a:2:{s:8:\"duration\";s:28:\"6 months after last activity\";s:11:\"description\";s:206:\"Contains information about the traffic source or campaign that directed user to the website. The cookie is set when the GA.js javascript is loaded and updated when data is sent to the Google Anaytics server\";}s:6:\"__utmv\";a:2:{s:8:\"duration\";s:27:\"2 years after last activity\";s:11:\"description\";s:185:\"Contains custom information set by the web developer via the _setCustomVar method in Google Analytics. This cookie is updated every time new data is sent to the Google Analytics server.\";}s:6:\"__utmx\";a:2:{s:8:\"duration\";s:9:\"18 months\";s:11:\"description\";s:78:\"Used to determine whether a user is included in an A / B or Multivariate test.\";}s:3:\"_ga\";a:2:{s:8:\"duration\";s:7:\"2 years\";s:11:\"description\";s:25:\"ID used to identify users\";}s:5:\"_gali\";a:2:{s:8:\"duration\";s:10:\"30 seconds\";s:11:\"description\";s:77:\"Used by Google Analytics to determine which links on a page are being clicked\";}s:4:\"_ga_\";a:2:{s:8:\"duration\";s:7:\"2 years\";s:11:\"description\";s:25:\"ID used to identify users\";}s:4:\"_gid\";a:2:{s:8:\"duration\";s:8:\"24 hours\";s:11:\"description\";s:58:\"ID used to identify users for 24 hours after last activity\";}s:4:\"_gat\";a:2:{s:8:\"duration\";s:8:\"1 minute\";s:11:\"description\";s:88:\"Used to monitor number of Google Analytics server requests when using Google Tag Manager\";}}}}s:9:\"marketing\";a:2:{s:14:\"facebook-pixel\";a:7:{s:4:\"name\";s:14:\"facebook-pixel\";s:7:\"service\";s:14:\"Facebook Pixel\";s:4:\"html\";s:473:\"&lt;script  type=&quot;litespeed/javascript&quot;&gt;!function(f,b,e,v,n,t,s){if(f.fbq)return;n=f.fbq=function(){n.callMethod?n.callMethod.apply(n,arguments):n.queue.push(arguments)};if(!f._fbq)f._fbq=n;n.push=n;n.loaded=!0;n.version=&#039;2.0&#039;;n.queue=[];t=b.createElement(e);t.async=!0;t.src=v;s=b.getElementsByTagName(e)[0];s.parentNode.insertBefore(t,s)}(window,document,&#039;script&#039;,&#039;https://connect.facebook.net/en_US/fbevents.js&#039;)&lt;/script&gt;\";s:4:\"logo\";s:47:\"https://cdn.wpconsent.com/services/facebook.png\";s:3:\"url\";s:35:\"https://www.facebook.com/policy.php\";s:11:\"description\";s:82:\"Facebook Pixel is a web analytics service that tracks and reports website traffic.\";s:7:\"cookies\";a:3:{s:4:\"_fbc\";a:2:{s:8:\"duration\";s:9:\"12 months\";s:11:\"description\";s:37:\"Used to track the last session visit.\";}s:4:\"_fbp\";a:2:{s:8:\"duration\";s:8:\"3 months\";s:11:\"description\";s:48:\"Used to track the user across multiple sessions.\";}s:2:\"fr\";a:2:{s:8:\"duration\";s:8:\"3 months\";s:11:\"description\";s:48:\"Used to track the user across multiple sessions.\";}}}s:9:\"recaptcha\";a:7:{s:4:\"name\";s:9:\"recaptcha\";s:7:\"service\";s:16:\"Google reCAPTCHA\";s:4:\"html\";s:233:\"&lt;script type=&quot;litespeed/javascript&quot; data-src=&quot;https://www.google.com/recaptcha/api.js?hl=en_US&amp;onload=recaptchaCallback&amp;render=explicit&amp;ver=2.0&quot; id=&quot;google-recaptcha-js&quot;&gt;&lt;/script&gt;\";s:4:\"logo\";s:48:\"https://cdn.wpconsent.com/services/recaptcha.png\";s:3:\"url\";s:0:\"\";s:11:\"description\";s:110:\"Google reCAPTCHA helps protect websites from spam and abuse by verifying user interactions through challenges.\";s:7:\"cookies\";a:1:{s:11:\"_GRECAPTCHA\";a:2:{s:8:\"duration\";s:8:\"179 days\";s:11:\"description\";s:116:\"Google reCAPTCHA sets a necessary cookie (_GRECAPTCHA) when executed for the purpose of providing its risk analysis.\";}}}}}s:15:\"services_needed\";a:7:{i:0;s:18:\"google-tag-manager\";i:1;s:16:\"google-analytics\";i:2;s:14:\"facebook-pixel\";i:3;s:8:\"comments\";i:4;s:11:\"woocommerce\";i:5;s:14:\"wp-consent-api\";i:9;s:9:\"recaptcha\";}}','auto');
