INSERT INTO `fqsi_options` (`option_id`, `option_name`, `option_value`, `autoload`) VALUES (245300,'wpconsent_scanner_1751289495533','a:2:{s:7:\"scripts\";a:3:{s:9:\"essential\";a:4:{s:8:\"comments\";a:7:{s:4:\"name\";s:8:\"comments\";s:7:\"service\";s:8:\"Comments\";s:4:\"html\";s:0:\"\";s:4:\"logo\";s:48:\"https://cdn.wpconsent.com/services/wordpress.png\";s:3:\"url\";s:0:\"\";s:11:\"description\";s:61:\"These cookies are needed for adding comments on this website.\";s:7:\"cookies\";a:3:{s:14:\"comment_author\";a:2:{s:8:\"duration\";s:7:\"Session\";s:11:\"description\";s:48:\"Used to track the user across multiple sessions.\";}s:20:\"comment_author_email\";a:2:{s:8:\"duration\";s:7:\"Session\";s:11:\"description\";s:48:\"Used to track the user across multiple sessions.\";}s:18:\"comment_author_url\";a:2:{s:8:\"duration\";s:7:\"Session\";s:11:\"description\";s:48:\"Used to track the user across multiple sessions.\";}}}s:11:\"woocommerce\";a:7:{s:4:\"name\";s:11:\"woocommerce\";s:7:\"service\";s:11:\"WooCommerce\";s:4:\"html\";s:0:\"\";s:4:\"logo\";s:50:\"https://cdn.wpconsent.com/services/woocommerce.png\";s:3:\"url\";s:0:\"\";s:11:\"description\";s:92:\"WooCommerce is a customizable eCommerce platform for building online stores using WordPress.\";s:7:\"cookies\";a:7:{s:23:\"wp_woocommerce_session_\";a:2:{s:8:\"duration\";s:6:\"2 days\";s:11:\"description\";s:120:\"Contains a unique code for each customer so that it knows where to find the cart data in the database for each customer.\";}s:27:\"woocommerce_recently_viewed\";a:2:{s:8:\"duration\";s:7:\"session\";s:11:\"description\";s:40:\"Powers the Recent Viewed Products widget\";}s:12:\"store_notice\";a:2:{s:8:\"duration\";s:7:\"session\";s:11:\"description\";s:45:\"Allows customers to dismiss the Store Notice.\";}s:32:\"woocommerce_snooze_suggestions__\";a:2:{s:8:\"duration\";s:6:\"2 days\";s:11:\"description\";s:70:\"Allows dashboard users to dismiss Marketplace suggestions, if enabled.\";}s:35:\"woocommerce_dis