ges.\";s:7:\"cookies\";a:2:{s:17:\"cookiePreferences\";a:2:{s:8:\"duration\";s:7:\"2 years\";s:11:\"description\";s:38:\"Registers cookie preferences of a user\";}s:2:\"td\";a:2:{s:8:\"duration\";s:7:\"session\";s:11:\"description\";s:115:\"Registers statistical data on users\' behaviour on the website. Used for internal analytics by the website operator.\";}}}}s:10:\"statistics\";a:1:{s:16:\"google-analytics\";a:7:{s:4:\"name\";s:16:\"google-analytics\";s:7:\"service\";s:16:\"Google Analytics\";s:4:\"html\";s:176:\"&lt;script type=&quot;litespeed/javascript&quot; data-src=&quot;https://www.googletagmanager.com/gtag/js?id=GT-NNMS2FV5&quot; id=&quot;google_gtagjs-js&quot;&gt;&lt;/script&gt;\";s:4:\"logo\";s:55:\"https://cdn.wpconsent.com/services/google-analytics.png\";s:3:\"url\";s:35:\"https://policies.google.com/privacy\";s:11:\"description\";s:110:\"Google Analytics is a powerful tool that tracks and analyzes website traffic for informed marketing decisions.\";s:7:\"cookies\";a:13:{s:5:\"_gac_\";a:2:{s:8:\"duration\";s:7:\"90 days\";s:11:\"description\";s:185:\"Contains information related to marketing campaigns of the user. These are shared with Google AdWords / Google Ads when the Google Ads and Google Analytics accounts are linked together.\";}s:6:\"__utma\";a:2:{s:8:\"duration\";s:27:\"2 years after last activity\";s:11:\"description\";s:38:\"ID used to identify users and sessions\";}s:6:\"__utmt\";a:2:{s:8:\"duration\";s:10:\"10 minutes\";s:11:\"description\";s:58:\"Used to monitor number of Google Analytics server requests\";}s:6:\"__utmb\";a:2:{s:8:\"duration\";s:30:\"30 minutes after last activity\";s:11:\"description\";s:225:\"Used to distinguish new sessions and visits. This cookie is set when the GA.js javascript library is loaded and there is no existing __utmb cookie. The cookie is updated every time data is sent to the Google Analytics server.\";}s:6:\"__utmc\";a:2:{s:8:\"duration\";s:24:\"End of session (browser)\";s:11:\"description\";s:155:\"Used