INSERT INTO `fqsi_options` (`option_id`, `option_name`, `option_value`, `autoload`) VALUES (338505,'advads_edd_sl_5d4fae668fa675929d258f339d2cb455','a:2:{s:7:\"timeout\";i:1755361079;s:5:\"value\";s:4608:\"{\"new_version\":\"3.0.5\",\"stable_version\":\"3.0.5\",\"name\":\"Tracking\",\"slug\":\"advanced-ads-tracking\",\"url\":\"https:\\/\\/wpadvancedads.com\\/add-ons\\/tracking\\/?changelog=1\",\"last_updated\":\"2025-07-28 14:29:45\",\"homepage\":\"https:\\/\\/wpadvancedads.com\\/add-ons\\/tracking\\/\",\"package\":\"https:\\/\\/wpadvancedads.com\\/edd-sl\\/package_download\\/MTc1NTkyOTg3OTpjNzI5OTgyMmZhNzBmYTdhMzM0MzhlM2I3OWIxYWRlNzo2Mzg6N2I3MmQ3ZGI0Nzk3MmVmODc4YjZiODgwZGE1NTgxNjY6aHR0cHNALy9hbnRpdmlydXNwb2ludC5vcmc6MA==\",\"download_link\":\"https:\\/\\/wpadvancedads.com\\/edd-sl\\/package_download\\/MTc1NTkyOTg3OTpjNzI5OTgyMmZhNzBmYTdhMzM0MzhlM2I3OWIxYWRlNzo2Mzg6N2I3MmQ3ZGI0Nzk3MmVmODc4YjZiODgwZGE1NTgxNjY6aHR0cHNALy9hbnRpdmlydXNwb2ludC5vcmc6MA==\",\"sections\":{\"description\":\"<p>Track your ads and limit them by clicks and impressions. Display the stats with beautiful graphs or analyze them on Google Analytics.<\\/p>\\n\",\"changelog\":\"<p> 3.0.5 (July 28, 2025) <\\/p>\\n<ul>\\n<li>Improvement: add undefined translations<\\/li>\\n<li>Improvement: prevent fatal error when tracking on invalid or non-ad entries<\\/li>\\n<li>Fix: resolve incorrect loading of tracking JS files<\\/li>\\n<\\/ul>\\n<p> 3.0.4 (June 25, 2025) <\\/p>\\n<ul>\\n<li>Improvement: add undefined translations<\\/li>\\n<li>Improvement: type safety in class-ad-limiter.php<\\/li>\\n<li>Improvement: Test plugin compatibility with WordPress 6.8.<\\/li>\\n<li>Fix: source URL tracking for cloaked links in debug logs<\\/li>\\n<li>Fix: add safety check in data handling<\\/li>\\n<li>Fix: the_ad_clicks shortcode render as plain text<\\/li>\\n<\\/ul>\\n<p> 3.0.3 (April 9, 2025) <\\/p>\\n<ul>\\n<li>Improvement: public report url rewriting with backward compatibility<\\/li>\\n<li>Fix: removed all license-related code from the addons as license management has been moved to the free version.<\\/li>\\n<li>Fix: quick edit for ads ignores tracking options and overwrites content<\\/li>\\n<\\/ul>\\n<p> 3.0.2 (March 18, 2025) <\\/p>\\n<ul>\\n<li>Improvement: update Arabic translations<\\/li>\\n<li>Fix: prevent fatal error on ad page<\\/li>\\n<\\/ul>\\n<p> 3.0.1 (March 12, 2025) <\\/p>\\n<ul>\\n<li>Fix: resolve PHP warnings during the update process<\\/li>\\n<li>Fix: correct an error in the loading of the language files<\\/li>\\n<li>Fix: display ad names in public reports and shareable links again<\\/li>\\n<\\/ul>\\n<p> 3.0.0 (March 10, 2025) <\\/p>\\n<ul>\\n<li>Feature: add best performing ads widget<\\/li>\\n<li>Improvement: add quick &amp; bulk edit for tracking options<\\/li>\\n<\\/ul>\\n\"},\"banners\":{\"high\":\"\",\"low\":\"\"},\"icons\":{\"1x\":\"https:\\/\\/wpadvancedads.com\\/wp-content\\/uploads\\/2021\\/10\\/Icon-Advanced-Ads-Tracking-128x128.png\",\"2x\":\"https:\\/\\/wpadvancedads.com\\/wp-content\\/uploads\\/2021\\/10\\/Icon-Advanced-Ads-Tracking-256x256.png\"},\"valid_until\":1786492799,\"description\":[\"<p>Track your ads and limit them by clicks and impressions. Display the stats with beautiful graphs or analyze them on Google Analytics.<\\/p>\\n\"],\"changelog\":[\"<p> 3.0.5 (July 28, 2025) <\\/p>\\n<ul>\\n<li>Improvement: add undefined translations<\\/li>\\n<li>Improvement: prevent fatal error when tracking on invalid or non-ad entries<\\/li>\\n<li>Fix: resolve incorrect loading of tracking JS files<\\/li>\\n<\\/ul>\\n<p> 3.0.4 (June 25, 2025) <\\/p>\\n<ul>\\n<li>Improvement: add undefined translations<\\/li>\\n<li>Improvement: type safety in class-ad-limiter.php<\\/li>\\n<li>Improvement: Test plugin compatibility with WordPress 6.8.<\\/li>\\n<li>Fix: source URL tracking for cloaked links in debug logs<\\/li>\\n<li>Fix: add safety check in data handling<\\/li>\\n<li>Fix: the_ad_clicks shortcode render as plain text<\\/li>\\n<\\/ul>\\n<p> 3.0.3 (April 9, 2025) <\\/p>\\n<ul>\\n<li>Improvement: public report url rewriting with backward compatibility<\\/li>\\n<li>Fix: removed all license-related code from the addons as license management has been moved to the free version.<\\/li>\\n<li>Fix: quick edit for ads ignores tracking options and overwrites content<\\/li>\\n<\\/ul>\\n<p> 3.0.2 (March 18, 2025) <\\/p>\\n<ul>\\n<li>Improvement: update Arabic translations<\\/li>\\n<li>Fix: prevent fatal error on ad page<\\/li>\\n<\\/ul>\\n<p> 3.0.1 (March 12, 2025) <\\/p>\\n<ul>\\n<li>Fix: resolve PHP warnings during the update process<\\/li>\\n<li>Fix: correct an error in the loading of the language files<\\/li>\\n<li>Fix: display ad names in public reports and shareable links again<\\/li>\\n<\\/ul>\\n<p> 3.0.0 (March 10, 2025) <\\/p>\\n<ul>\\n<li>Feature: add best performing ads widget<\\/li>\\n<li>Improvement: add quick &amp; bulk edit for tracking options<\\/li>\\n<\\/ul>\\n\"],\"plugin\":\"advanced-ads-tracking\\/tracking.php\",\"id\":\"advanced-ads-tracking\\/tracking.php\",\"tested\":null,\"requires\":\"\",\"requires_php\":\"\"}\";}','off');
INSERT INTO `fqsi_options` (`option_id`, `option_name`, `option_value`, `autoload`) VALUES (338541,'woocommerce_feature_experimental-iapi-mini-cart_enabled','no','on');
INSERT INTO `fqsi_options` (`option_id`, `option_name`, `option_value`, `autoload`) VALUES (338595,'advads_edd_sl_6d85b2a7f03d0dd3cedb1283153091b6','a:2:{s:7:\"timeout\";i:1755361077;s:5:\"value\";s:24225:\"{\"new_version\":\"2.0.5\",\"stable_version\":\"2.0.5\",\"name\":\"AMP Ads\",\"slug\":\"advanced-ads-responsive\",\"url\":\"https:\\/\\/wpadvancedads.com\\/add-ons\\/amp-ads\\/?changelog=1\",\"last_updated\":\"2025-08-05 18:50:08\",\"homepage\":\"https:\\/\\/wpadvancedads.com\\/add-ons\\/amp-ads\\/\",\"package\":\"https:\\/\\/wpadvancedads.com\\/edd-sl\\/package_download\\/MTc1NTkyOTg3NjpjNzI5OTgyMmZhNzBmYTdhMzM0MzhlM2I3OWIxYWRlNzo2Nzg6NDY1NmM5NmQ3YWNiMmUyNjZjZTc4ODEzNDViYTk4Njc6aHR0cHNALy9hbnRpdmlydXNwb2ludC5vcmc6MA==\",\"download_link\":\"https:\\/\\/wpadvancedads.com\\/edd-sl\\/package_download\\/MTc1NTkyOTg3NjpjNzI5OTgyMmZhNzBmYTdhMzM0MzhlM2I3OWIxYWRlNzo2Nzg6NDY1NmM5NmQ3YWNiMmUyNjZjZTc4ODEzNDViYTk4Njc6aHR0cHNALy9hbnRpdmlydXNwb2ludC5vcmc6MA==\",\"sections\":{\"description\":\"<p>Enhance your ad integration with AMP Ads by Advanced Ads. Experience effortless AMP compatibility, precise ad targeting, and streamlined AdSense ad conversion, all in one add-on. <\\/p>\\n\",\"changelog\":\"<p> 2.0.3 <\\/p>\\n<ul>\\n<li>Fix: allow AMP placement condition to be saved again<\\/li>\\n<\\/ul>\\n<p> 2.0.2 <\\/p>\\n<ul>\\n<li>Fix: correct the license handling<\\/li>\\n<\\/ul>\\n<p> 2.0.1 <\\/p>\\n<ul>\\n<li>Fix: prevent a fatal error on activation<\\/li>\\n<\\/ul>\\n<p> 2.0.0 <\\/p>\\n<ul>\\n<li>Feature: achieve full compatibility with Advanced Ads 2.0<\\/li>\\n<li>Improvement: enhance performance and efficiency with new codebase<\\/li>\\n<\\/ul>\\n<p> 1.12.4 <\\/p>\\n<ul>\\n<li>Improvement: update Arabic, Danish, German, German (formal), German (Austria, Switzerland), Greek, Italian, Slovenian translations<\\/li>\\n<li>Improvement: add compatibility code for Advanced Ads 2.0<\\/li>\\n<\\/ul>\\n<p> 1.12.3 <\\/p>\\n<ul>\\n<li>Fix: prevent PHP 8 deprecation notices<\\/li>\\n<\\/ul>\\n<p> 1.12.2 <\\/p>\\n<ul>\\n<li>Fix: show the licence field when Advanced Ads Pro is disabled<\\/li>\\n<\\/ul>\\n<p> 1.12.1 <\\/p>\\n<ul>\\n<li>Fix: prevent notification from showing infinitely<\\/li>\\n<\\/ul>\\n<p> 1.12.0 <\\/p>\\n<ul>\\n<li>Feature: rebrand add-on as \\u201cAdvanced Ads AMP Ads\\u201d<\\/li>\\n<li>Feature: move the Browser Width condition to Advanced Ads Pro<\\/li>\\n<li>Feature: move feature to reload ads on screen size change to Advanced Ads Pro<\\/li>\\n<li>Feature: move feature to enforce responsive image ads for themes without support to Advanced Ads Pro<\\/li>\\n<li>Feature: remove the size assistant feature that helped determine the size of ads in the frontend<\\/li>\\n<\\/ul>\\n<p> 1.11.0 <\\/p>\\n<ul>\\n<li>Improvement: update AdSense code script tags to align with their latest version<\\/li>\\n<li>Improvement: remove an old version of the browser width condition that was deprecated in 2015<\\/li>\\n<li>Improvement: deprecate the Responsive Ads list. See the removal schedule on <a href=\\\"https:\\/\\/wpadvancedads.com\\/manual\\/deprecated-features\\/\\\">https:\\/\\/wpadvancedads.com\\/manual\\/deprecated-features\\/<\\/a>.<\\/li>\\n<li>Improvement: update UI of an AMP related notice on the ad edit page<\\/li>\\n<li>Improvement: update Arabic, German, Slovenian translations<\\/li>\\n<li>Fix: pass empty string instead of null to add_submenu_page()<\\/li>\\n<\\/ul>\\n<p> 1.10.6 <\\/p>\\n<ul>\\n<li>Improvement: add Slovenian translations<\\/li>\\n<li>Improvement: update Danish translations<\\/li>\\n<li>Fix: prevent undefined index notice<\\/li>\\n<\\/ul>\\n<p> 1.10.5 <\\/p>\\n<ul>\\n<li>Fix: remove workflow directory from plugin<\\/li>\\n<\\/ul>\\n<p> 1.10.4 <\\/p>\\n<ul>\\n<li>Improvement: add German (Austria, Switzerland), Greek translations<\\/li>\\n<li>Fix: prevent removing advanced default size of responsive AdSense ads when re-saving ad<\\/li>\\n<\\/ul>\\n<p> 1.10.3 <\\/p>\\n<ul>\\n<li>Improvement: add Arabic translations<\\/li>\\n<li>Improvement: update Polish translations<\\/li>\\n<li>Fix: prevent PHP 8 deprecation notices<\\/li>\\n<\\/ul>\\n<p> 1.10.2 <\\/p>\\n<ul>\\n<li>fix flash of unstyled content (FOUC) in firefox<\\/li>\\n<\\/ul>\\n<p> 1.10.1 <\\/p>\\n<ul>\\n<li>updated Vietnamese and Danish translations<\\/li>\\n<\\/ul>\\n<p> 1.10.0 <\\/p>\\n<ul>\\n<li>moved \\\"Enable AMP Auto ads\\\" option to Advanced Ads 1.24.0<\\/li>\\n<\\/ul>\\n<p> 1.9.2 <\\/p>\\n<ul>\\n<li>compatibility with the official AMP plugin version 2.0<\\/li>\\n<\\/ul>\\n<p> 1.9.1 <\\/p>\\n<ul>\\n<li>adjusted AdSense AMP codes to work with responsive widths after AdSense seems to have either changed something or introduce a bug \\u2013 so this fix might just be temporary<\\/li>\\n<li>moved AMP Auto ads option to existing Auto ads option. Needs Advanced Ads 1.17.12<\\/li>\\n<li>prepared AMP tracking method for Tracking 2.0<\\/li>\\n<\\/ul>\\n<p> 1.9 <\\/p>\\n<ul>\\n<li>all AdSense ad units have an appropriate AMP version now<\\/li>\\n<li>removed fallback option for AdSense ads without an AMP version since it is no longer needed<\\/li>\\n<li>fixed issue with AMP Auto ads and the AMP for WP plugin<\\/li>\\n<li>fixed issue with AMP Auto ads in Reader mode of the official AMP plugin<\\/li>\\n<\\/ul>\\n<p> 1.8.10 <\\/p>\\n<ul>\\n<li>added compatibility with Advanced Ads Pro to use conditions in placements<\\/li>\\n<\\/ul>\\n<p> 1.8.9 <\\/p>\\n<ul>\\n<li>added compatibility to work with Advanced Ads Pro 2.5 on AMP pages<\\/li>\\n<\\/ul>\\n<p> 1.8.8 <\\/p>\\n<ul>\\n<li>convert responsive full-width AdSense ads to AMP if possible<\\/li>\\n<\\/ul>\\n<p> 1.8.7 <\\/p>\\n<ul>\\n<li>fixed issue on plugin activation caused by changes in 1.8.6<\\/li>\\n<\\/ul>\\n<p> 1.8.6 <\\/p>\\n<ul>\\n<li>compatibility with new versions of the AMP Plugin for WordPress: made AMP Auto ads for AdSense work, prevented validation errors<\\/li>\\n<li>added Polish translations<\\/li>\\n<li>updated Italian translations<\\/li>\\n<li>updated German translations<\\/li>\\n<\\/ul>\\n<p> 1.8.5 <\\/p>\\n<ul>\\n<li>added German translations<\\/li>\\n<li>added compatibility with latest versions of \\\"Accelerated Mobile Pages for WP\\\" plugin<\\/li>\\n<\\/ul>\\n<p> 1.8.4 <\\/p>\\n<ul>\\n<li>fixed AMP option name that broke the AdSense background option in the basic plugin<\\/li>\\n<\\/ul>\\n<p> 1.8.3 <\\/p>\\n<ul>\\n<li>fixed resize assistant causing responsive ads and AdSense not to show up<\\/li>\\n<\\/ul>\\n<p> 1.8.2 <\\/p>\\n<ul>\\n<li>removed comment that caused a false positive warning from WordFence \\u2013 there was never Malware here<\\/li>\\n<\\/ul>\\n<p> 1.8.1 <\\/p>\\n<ul>\\n<li>added option for fallback width<\\/li>\\n<li>compatibility with SmartMag theme<\\/li>\\n<li>added Italian translation<\\/li>\\n<li>added French translation<\\/li>\\n<\\/ul>\\n<p> 1.8 <\\/p>\\n<ul>\\n<li>implemented AMP Auto ads for Adsense<\\/li>\\n<li>added posibility to set fallback browser width<\\/li>\\n<\\/ul>\\n<p> 1.7.3 <\\/p>\\n<ul>\\n<li>set ADVANCED_ADS_RESPONSIVE_DISABLE_BROWSER_WIDTH constant to disable Browser Width condition (and not save any cookies)<\\/li>\\n<\\/ul>\\n<p> 1.7.2 <\\/p>\\n<ul>\\n<li>added possibility to customize Adsense Responsive Matched Content unit<\\/li>\\n<\\/ul>\\n<p> 1.7.1 <\\/p>\\n<ul>\\n<li>fixed an issue caused by the \\\"AMP for WP\\\" plugin with advanced Responsive Adsense ads<\\/li>\\n<\\/ul>\\n<p> 1.7 <\\/p>\\n<ul>\\n<li>automatically convert all AdSense ads into an AMP format, see <a href=\\\"https:\\/\\/wpadvancedads.com\\/manual\\/amp-adsense-wordpress\\/\\\">https:\\/\\/wpadvancedads.com\\/manual\\/amp-adsense-wordpress\\/<\\/a><\\/li>\\n<li>updated German translation<\\/li>\\n<\\/ul>\\n<p> 1.6.2 <\\/p>\\n<ul>\\n<li>compatibility with handling responsive image ads in Advanced Ads version 1.8.21<\\/li>\\n<\\/ul>\\n<p> 1.6.1 <\\/p>\\n<ul>\\n<li>don\\u2019t track AMP impressions locally in Tracking add-on if Analytics method is selected<\\/li>\\n<li>updated Spanish translation<\\/li>\\n<li>secured backward compatibility with older versions of the basic plugin<\\/li>\\n<\\/ul>\\n<p> 1.6 <\\/p>\\n<ul>\\n<li>allow all ad types on AMP pages since the major AMP plugins filter invalid code automatically<\\/li>\\n<li>please reach out to us if you experience any issues with this new default behavior<\\/li>\\n<\\/ul>\\n<p> 1.5.2 <\\/p>\\n<ul>\\n<li>hotfix to save browser width cookie correctly<\\/li>\\n<\\/ul>\\n<p> 1.5.1 <\\/p>\\n<ul>\\n<li>removed old overview widget logic<\\/li>\\n<li>do not reload ads on iOS when the \'Reload ads on resize\' option is enabled and the user scrolls the page<\\/li>\\n<li>allow image ad type on AMP pages also outside of \'the_content\'<\\/li>\\n<\\/ul>\\n<p> 1.5 <\\/p>\\n<ul>\\n<li>moved AMP check function to basic plugin<\\/li>\\n<li>moved AMP warning for AdSense to new ad notices section<\\/li>\\n<li>minor fixes to textdomains and labels<\\/li>\\n<\\/ul>\\n<p> 1.4.5 <\\/p>\\n<ul>\\n<li>reload ads on screen resize is now optional and off by default, since it caused issues with some kinds of ads<\\/li>\\n<li>updated pot file and German translation<\\/li>\\n<\\/ul>\\n<p> 1.4.4 <\\/p>\\n<ul>\\n<li>use cookie functions from basic plugin<\\/li>\\n<li>trigger event when screen is resized to reload ads when cache-busting is enabled<\\/li>\\n<li>fixed dependency with basic plugin<\\/li>\\n<\\/ul>\\n<p> 1.4.3 <\\/p>\\n<ul>\\n<li>made compatible with AdSense Matched Content<\\/li>\\n<li>fixed possible issue when jQuery is not yet loaded<\\/li>\\n<\\/ul>\\n<p> 1.4.2 <\\/p>\\n<ul>\\n<li>show warning on AdSense types that don\\u2019t support AMP<\\/li>\\n<li>fixed positioning and label size of AMP ads<\\/li>\\n<\\/ul>\\n<p> 1.4.1 <\\/p>\\n<ul>\\n<li>added support for WP AMP plugin<\\/li>\\n<\\/ul>\\n<p> 1.4 <\\/p>\\n<ul>\\n<li>added automatic AMP support for AdSense<\\/li>\\n<li>added AMP Display Condition<\\/li>\\n<li>added AMP ad type to allow any ad network\\u2019s AMP format<\\/li>\\n<\\/ul>\\n<p> 1.3.2 <\\/p>\\n<ul>\\n<li>fix to keep additional sizes for advanced responsive AdSense ads<\\/li>\\n<\\/ul>\\n<p> 1.3.1 <\\/p>\\n<ul>\\n<li>fix to run Responsive add-on along with WP Mobile Detect plugin<\\/li>\\n<\\/ul>\\n<p> 1.3 <\\/p>\\n<ul>\\n<li>added option to force responsive image ads if not supported by the theme<\\/li>\\n<li>added tablet detection<\\/li>\\n<li>set default AdSense sizes to rectangle, vertical or horizontal<\\/li>\\n<\\/ul>\\n<p> 1.2.9 <\\/p>\\n<ul>\\n<li>fixed link to responsive overview page on blogs in subdirectories<\\/li>\\n<li>added Spanish and German localization<\\/li>\\n<\\/ul>\\n<p> 1.2.8 <\\/p>\\n<ul>\\n<li>updated user rights check<\\/li>\\n<li>fix for displaying AdSense ads as non-superadmin<\\/li>\\n<li>fix frontend helper showing an empty width in Chrome browser<\\/li>\\n<li>fix frontend helper working with cache busting in Pro<\\/li>\\n<li>fix for saving current browser width if tooltip is enabled<\\/li>\\n<\\/ul>\\n<p> 1.2.7 <\\/p>\\n<ul>\\n<li>fix for manually sized responsive ads<\\/li>\\n<\\/ul>\\n<p> 1.2.6 <\\/p>\\n<ul>\\n<li>fixed manual sizing for cache-busted ads<\\/li>\\n<li>fixed saved width on iPhone<\\/li>\\n<\\/ul>\\n<p> 1.2.5 <\\/p>\\n<ul>\\n<li>prevent ads from covering the frontend assistant<\\/li>\\n<\\/ul>\\n<p> 1.2.4 <\\/p>\\n<ul>\\n<li>show warning if Advanced Ads is not installed<\\/li>\\n<li>changed class of active buttons to align with main plugin css<\\/li>\\n<li>updated plugin link<\\/li>\\n<li>added plugin link to license page<\\/li>\\n<\\/ul>\\n<p> 1.2.3 <\\/p>\\n<ul>\\n<li>moved licensing code to main plugin<\\/li>\\n<li>added adsbygoogle library reference<\\/li>\\n<\\/ul>\\n<p> 1.2.2 <\\/p>\\n<ul>\\n<li>the list of responsive ads now only includes the new visitor conditions type<\\/li>\\n<\\/ul>\\n<p> 1.2.1 <\\/p>\\n<ul>\\n<li>moved browser width conditions to new visitor conditions api<\\/li>\\n<li>updated all class names from \\\"Advads_\\\" to \\\"Advanced<em>Ads<\\/em>\\\"<\\/li>\\n<li>fixed minor error message in dashboard<